test_config.test_file:
import { render, screen } from '@testing-library/react';
import '@testing-library/jest-dom';
import App from './App';

describe('Sticky Sidebar Layout', () => {
  beforeEach(() => {
    render(<App />);
  });

  it('layout uses CSS Grid', () => {
    expect(getComputedStyle(screen.getByTestId('layout')).display).toBe('grid');
  });

  it('sidebar is sticky', () => {
    const sidebar = screen.getByTestId('sidebar');
    expect(getComputedStyle(sidebar).position).toBe('sticky');
  });

  it('sidebar sticks to top', () => {
    const sidebar = screen.getByTestId('sidebar');
    expect(getComputedStyle(sidebar).top).toBe('0px');
  });

  it('sidebar has start alignment', () => {
    const sidebar = screen.getByTestId('sidebar');
    expect(getComputedStyle(sidebar).alignSelf).toBe('start');
  });

  it('header has dark background', () => {
    const header = screen.getByTestId('header');
    expect(getComputedStyle(header).backgroundColor).toBe('rgb(31, 41, 55)');
  });

  it('header text is white', () => {
    const header = screen.getByTestId('header');
    expect(getComputedStyle(header).color).toBe('rgb(255, 255, 255)');
  });

  it('header spans full width', () => {
    const header = screen.getByTestId('header');
    const gc = getComputedStyle(header).gridColumn;
    expect(gc).toMatch(/1\s*\/\s*-1|1\s*\/\s*3|span\s+2/);
  });

  it('sidebar has light background', () => {
    expect(getComputedStyle(screen.getByTestId('sidebar')).backgroundColor).toBe('rgb(249, 250, 251)');
  });

  it('footer has grey background', () => {
    expect(getComputedStyle(screen.getByTestId('footer')).backgroundColor).toBe('rgb(243, 244, 246)');
  });
});

