.layout {
  display: grid;
  grid-template-columns: 16rem 1fr;
}

.layout__header {
  grid-column: 1 / -1;
  background-color: #1f2937;
  color: #ffffff;
  padding: 1rem;
}

.layout__header h1 {
  margin: 0;
  font-size: 1.125rem;
}

.layout__sidebar {
  position: sticky;
  top: 0;
  align-self: start;
  max-height: 100vh;
  overflow-y: auto;
  background-color: #f9fafb;
  padding: 1.5rem;
  border-right: 1px solid #e5e7eb;
}

.layout__sidebar h2 {
  margin: 0 0 1rem;
  font-size: 0.9375rem;
  font-weight: 600;
  color: #111827;
}

.layout__sidebar ul {
  list-style: none;
  padding: 0;
  margin: 0;
}

.layout__sidebar li {
  margin-bottom: 0.5rem;
}

.layout__sidebar a {
  color: #3b82f6;
  text-decoration: none;
  font-size: 0.875rem;
}

.layout__main {
  padding: 2rem;
}

.layout__footer {
  grid-column: 1 / -1;
  background-color: #f3f4f6;
  padding: 1rem;
}

.layout__footer p {
  margin: 0;
  font-size: 0.8125rem;
  color: #6b7280;
}
